  function resetNintendo() {
    if (!globals.window["NINTENDO_RUNNING"]) {
      return
    }

    globals.window["NINTENDO_AUDIO_CONTEXT"].suspend()
    globals.window["NINTENDO_AUDIO_CONTEXT"].resume()
    Module._retro_reset()
  }

  globals.window["resetNintendo"] = resetNintendo

  function toggleSoundNintendo() {
    if (!globals.window["NINTENDO_RUNNING"]) {
      return
    }

    globals.window["NINTENDO_MUTED"] = !globals.window["NINTENDO_MUTED"]
    if (globals.window["NINTENDO_GAIN_NODE"]) {
      globals.window["NINTENDO_GAIN_NODE"].gain.value = globals.window[
        "NINTENDO_MUTED"
      ]
        ? 0
        : 1
    }
  }

  globals.window["toggleSoundNintendo"] = toggleSoundNintendo

  function downloadStateNintendo() {
    if (!globals.window["NINTENDO_RUNNING"]) {
      return
    }

    var size = Module._retro_serialize_size()
    if (size <= 0) {
      return
    }

    var bufPtr = Module._malloc(size)
    var ok = Module._retro_serialize(bufPtr, size)
    if (!ok) {
      Module._free(bufPtr)
      return
    }

    var data = new Uint8Array(Module.HEAPU8.buffer, bufPtr, size).slice()
    Module._free(bufPtr)

    var blob = new Blob([data], { type: "application/octet-stream" })
    var url = URL.createObjectURL(blob)
    var a = document.createElement("a")
    a.href = url
    a.download =
      globals.window["NINTENDO_GAME_NAME"].replace(/\.\w+$/, "") + ".state"
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    URL.revokeObjectURL(url)
  }

  globals.window["downloadStateNintendo"] = downloadStateNintendo

  function uploadStateNintendo() {
    try {
      if (!globals.window["NINTENDO_RUNNING"]) {
        return
      }

      var input = globals.document.createElement("input")
      input.type = "file"
      input.accept = ".state"

      input.addEventListener("change", function (event) {
        var file = event.target.files[0]
        if (!file) {
          return
        }

        var reader = new FileReader()
        reader.addEventListener("load", function (e) {
          try {
            var data = new Uint8Array(e.target.result)
            var bufPtr = Module._malloc(data.length)
            Module.HEAPU8.set(data, bufPtr)
            Module._retro_unserialize(bufPtr, data.length)
            Module._free(bufPtr)

            // Reset audio timing to avoid crackling after state load
            globals.window["NINTENDO_AUDIO_NEXT_TIME"] = 0
            globals.window["NINTENDO_AUDIO_BUFFER_QUEUE"] = []
          } catch (error) {
            //
          }
        })

        reader.readAsArrayBuffer(file)
      })

      input.click()
    } catch (err) {
      //
    }
  }

  globals.window["uploadStateNintendo"] = uploadStateNintendo

  function requestEmulatorFullscreenNintendo() {
    try {
      if (!globals.window["NINTENDO_RUNNING"]) {
        return
      }

      var docEl = document.getElementById(globals.window["NINTENDO_CONTAINER"])

      var requestFull =
        docEl.requestFullscreen ||
        docEl.mozRequestFullScreen ||
        docEl.webkitRequestFullscreen ||
        docEl.msRequestFullscreen

      var isFull =
        docEl.fullscreenElement ||
        docEl.mozFullScreenElement ||
        docEl.webkitFullscreenElement ||
        docEl.msFullscreenElement

      if (!isFull) {
        if (requestFull) {
          requestFull.call(docEl)
        }
      }
    } catch (err) {
      //
    }
  }

  globals.window["requestEmulatorFullscreenNintendo"] =
    requestEmulatorFullscreenNintendo
